import Image from "next/image";

/**
 * Brand logos used by Card 1 (ToolsCard) in the Problem section.
 *
 * Two rendering strategies, one shared visual:
 *   • ChatGPT / Angular / Node.js / Blank — pure inline SVG (path data lifted
 *     1:1 from the Figma export). ~5KB total, zero network cost, crisp at any
 *     DPR.
 *   • Google / AWS — next/image pointed at a static raster in /public/problem/.
 *     The Figma export ships these two as embedded PNGs (Google = 56KB,
 *     AWS = 236KB) because the source brand artwork is raster; next/image
 *     re-encodes them to WebP at render size, so the browser actually sees
 *     ~5–10KB each and they stay sharp.
 *
 * From the consumer's side (ToolsCard.tsx) it's one uniform import — every
 * component renders a 62 × 62 #EFEFEF disc, just with different insides.
 */

const BADGE = { size: 62, bg: "#efefef" } as const;

/* HTML wrapper for non-SVG logos (same visual as LogoShell). */
type BadgeFrameProps = {
  readonly label: string;
  readonly children: React.ReactNode;
};

function BadgeFrame({ label, children }: BadgeFrameProps) {
  return (
    <div
      role="img"
      aria-label={label}
      className="flex shrink-0 items-center justify-center rounded-full"
      style={{
        width: BADGE.size,
        height: BADGE.size,
        backgroundColor: BADGE.bg,
      }}
    >
      {children}
    </div>
  );
}

type LogoShellProps = {
  readonly label: string;
  readonly children: React.ReactNode;
  readonly viewBox?: string;
};

/**
 * Thin wrapper around the badge SVG. Keeps the aria-label + sizing + disc
 * background in one place, lets each logo component focus on the glyph.
 */
function LogoShell({ label, children, viewBox = "0 0 62 62" }: LogoShellProps) {
  return (
    <svg
      role="img"
      aria-label={label}
      width={BADGE.size}
      height={BADGE.size}
      viewBox={viewBox}
      fill="none"
      className="shrink-0"
    >
      <rect width="61.6" height="61.6" rx="30.8" fill={BADGE.bg} />
      {children}
    </svg>
  );
}

