/* ─── AWS ───────────────────────────────────────────────────── */
/**
 * Amazon Web Services — served as an optimized raster (WebP over the wire)
 * because the brand wordmark uses proprietary Amazon Ember glyphs that can't
 * be reliably vectorized by hand. next/image re-encodes the 236KB source PNG
 * to ~5-8KB WebP at badge size.
 */
export function AwsLogo() {
  return (
    <BadgeFrame label="AWS">
      <Image
        src="/problem/aws.png"
        alt=""
        width={42}
        height={28}
        sizes="42px"
        className="h-auto w-[42px] object-contain"
      />
    </BadgeFrame>
  );
}

/* ─── Google ────────────────────────────────────────────────── */
/**
 * Google wordmark — served as an optimized raster (WebP over the wire) for
 * the same reason as AWS: the Product Sans letterforms are proprietary, so
 * a hand-vectorized approximation drifts visibly from the real brand.
 * next/image re-encodes the 56KB source PNG to ~3-5KB WebP at badge size.
 */
export function GoogleLogo() {
  return (
    <BadgeFrame label="Google">
      <Image
        src="/problem/google.png"
        alt=""
        width={38}
        height={38}
        sizes="38px"
        className="h-[38px] w-[38px] object-contain"
      />
    </BadgeFrame>
  );
}

/* ─── Blank trailing badge ──────────────────────────────────── */
export function BlankLogo() {
  // Per Figma blank.svg — plain disc at 50% opacity. Decorative: hidden from AT.
  return (
    <svg
      aria-hidden
      width={BADGE.size}
      height={BADGE.size}
      viewBox="0 0 62 62"
      fill="none"
      className="shrink-0"
      style={{ opacity: 0.5 }}
    >
      <rect width="61.6" height="61.6" rx="30.8" fill={BADGE.bg} />
    </svg>
  );
}
